#include <stdio.h>
int main() {
    int N, L, R;
    scanf("%d %d %d", &N, &L, &R);
    long long int lengths[N];
    for (int i = 0; i < N; i++) {
        scanf("%lld", &lengths[i]);
    }
    int count = 0;
    for (long long int x = L; x <= R; x++) {
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (x + lengths[i] > lengths[j] && x + lengths[j] > lengths[i] && lengths[i] + lengths[j] > x) {
                    count++;
                    break;
                }
            }
        }
    }
    printf("%d\n", count);
    return 0;
}

